SELECT TOP 1 NT.[ID], NT.[SUBJECT_TEMPLATE], NT.[MESSAGE_TEMPLATE] 
FROM [NOTIFICATION_TEMPLATES] NT 
WHERE NT.[IsDeleted] = 0 
	AND NT.[NOTIFICATION_TYPE] = @PRM_NOTIFICATION_TEMPLATE_NOTIFICATION_TYPE 
	AND NT.[CHANNEL] = @PRM_NOTIFICATION_TEMPLATE_CHANNEL 
ORDER BY NT.[ID] 